// Determine task based on event type
const input = $input.first().json;
const event_type = input.event_type;
const payload = input.payload;

let task = null;

switch(event_type) {
  case 'lead.created':
    task = {
      title: 'New Lead: Initial Contact',
      description: `New lead ${payload.first_name || ''} ${payload.last_name || ''} needs initial contact.`,
      priority: 'high',
      due_in_minutes: 30,
      entity_type: 'lead',
      entity_id: input.entity_id,
      category: 'sales'
    };
    break;

  case 'quote.sent':
    task = {
      title: 'Quote Follow-up Call',
      description: `Quote sent for ${payload.line_of_business}. Schedule follow-up call.`,
      priority: 'high',
      due_in_minutes: 1440, // 24 hours
      entity_type: 'quote',
      entity_id: input.entity_id,
      category: 'sales'
    };
    break;

  case 'document.uploaded':
    if (payload.classification === 'unknown' || !payload.classification) {
      task = {
        title: 'Classify Uploaded Document',
        description: `Document "${payload.filename}" needs manual classification.`,
        priority: 'low',
        due_in_minutes: 480, // 8 hours
        entity_type: 'document',
        entity_id: input.entity_id,
        category: 'admin'
      };
    }
    break;

  case 'policy.activated':
    task = {
      title: 'Welcome Call - New Policy',
      description: `Policy ${payload.policy_number} is now active. Make welcome call.`,
      priority: 'medium',
      due_in_minutes: 2880, // 48 hours
      entity_type: 'policy',
      entity_id: input.entity_id,
      category: 'service'
    };
    break;

  case 'ticket.created':
    if (payload.priority === 'urgent') {
      task = {
        title: `URGENT: ${payload.subject}`,
        description: `Service ticket ${payload.ticket_number} requires immediate attention.`,
        priority: 'urgent',
        due_in_minutes: 60,
        entity_type: 'service_ticket',
        entity_id: input.entity_id,
        category: 'service'
      };
    }
    break;
}

return {
  should_create_task: task !== null,
  task: task,
  agency_workspace_id: input.agency_workspace_id,
  event_type: event_type
};
